   197→    // Check recruiter auth
   198→    document.addEventListener('DOMContentLoaded', async () => {
   199→      const user = await checkAuth();
   200→      if (!user) {
   201→        window.location.href = '/login.html';
   202→        return;
   203→      }
   204→
   205→      // Verify recruiter role
   206→      if (!user.company_id && user.role !== 'recruiter') {
   207→        window.location.href = '/dashboard.html';
   208→        return;
   209→      }
   210→
   211→      // Update user info
   212→      const name = user.name || user.email.split('@')[0];
   213→      document.getElementById('user-name').textContent = name;
   214→      document.getElementById('user-avatar').textContent = name.charAt(0).toUpperCase();
   215→      document.getElementById('company-name').textContent = user.company_name || 'Company';
   216→      document.getElementById('dropdown-user-name').textContent = name;
   217→      document.getElementById('dropdown-user-email').textContent = user.email;
   218→
   219→      // Setup user menu dropdown
   220→      const userMenuToggle = document.getElementById('user-menu-toggle');
   221→      const userDropdownMenu = document.getElementById('user-dropdown-menu');
   222→      if (userMenuToggle && userDropdownMenu) {
   223→        userMenuToggle.addEventListener('click', (e) => {
   224→          e.stopPropagation();
   225→          userDropdownMenu.classList.toggle('active');
   226→        });
   227→
   228→        document.addEventListener('click', () => {
   229→          userDropdownMenu.classList.remove('active');
   230→        });
   231→
   232→        userDropdownMenu.addEventListener('click', (e) => {
   233→          e.stopPropagation();
   234→        });
   235→      }
   236→
   237→      // Load dashboard data
   238→      loadRecruiterDashboard();
   239→    });
