   241→    async function loadRecruiterDashboard() {
   242→      try {
   243→        const data = await apiCall('/recruiter/dashboard');
   244→        if (!data) return;
   245→
   246→        // Update TrustScore
   247→        if (data.trust_score) {
   248→          document.getElementById('trustscore-value').textContent = data.trust_score.total_score;
   249→          document.getElementById('trustscore-tier').textContent = data.trust_score.tier_label;
   250→          document.getElementById('trustscore-tier').style.background = data.trust_score.tier_color;
   251→        }
   252→
   253→        // Update stats
   254→        document.getElementById('active-jobs').textContent = data.job_stats?.active_jobs || 0;
   255→        document.getElementById('total-applications').textContent = data.application_stats?.total_applications || 0;
   256→        document.getElementById('new-applications').textContent = data.application_stats?.new_applications || 0;
   257→
   258→        const interviewed = parseInt(data.application_stats?.interviewed) || 0;
   259→        const offered = parseInt(data.application_stats?.offered) || 0;
   260→        const ratio = interviewed > 0 ? ((offered / interviewed) * 100).toFixed(0) + '%' : '-';
   261→        document.getElementById('offer-ratio').textContent = ratio;
   262→
   263→        // Render upcoming interviews
   264→        renderUpcomingInterviews(data.upcoming_interviews || []);
   265→
   266→        // Render recent applications
   267→        renderRecentApplications(data.recent_applications || []);
   268→
   269→      } catch (err) {
   270→        console.error('Failed to load dashboard:', err);
   271→      }
   272→    }
   273→
   274→    function renderUpcomingInterviews(interviews) {
   275→      const container = document.getElementById('upcoming-interviews');
   276→
   277→      if (interviews.length === 0) {
   278→        container.innerHTML = `
   279→          <div class="empty-state">
   280→            <p>No upcoming interviews</p>
   281→            <a href="/recruiter-applications.html" class="btn btn-ghost btn-sm">Review applications</a>
   282→          </div>
   283→        `;
   284→        return;
   285→      }
   286→
   287→      container.innerHTML = interviews.map(i => `
   288→        <div class="interview-item">
   289→          <div class="interview-time">
   290→            <span class="date">${new Date(i.scheduled_at).toLocaleDateString()}</span>
   291→            <span class="time">${new Date(i.scheduled_at).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}</span>
   292→          </div>
   293→          <div class="interview-info">
   294→            <span class="candidate-name">${i.candidate_name}</span>
   295→            <span class="job-title">${i.job_title}</span>
   296→          </div>
   297→          <span class="interview-type-badge ${i.interview_type}">${i.interview_type}</span>
   298→        </div>
   299→      `).join('');
   300→    }
   301→
   302→    function renderRecentApplications(applications) {
   303→      const container = document.getElementById('recent-applications');
   304→
   305→      if (applications.length === 0) {
   306→        container.innerHTML = `
   307→          <div class="empty-state">
   308→            <p>No applications yet</p>
   309→            <a href="/job-create.html" class="btn btn-ghost btn-sm">Post a job</a>
   310→          </div>
   311→        `;
   312→        return;
   313→      }
   314→
   315→      container.innerHTML = applications.map(a => `
   316→        <div class="application-item">
   317→          <div class="candidate-info">
   318→            <span class="candidate-name">${a.candidate_name}</span>
