   268→  return 'status-pending';
   269→}
   270→
   271→function getStatusText(status) {
   272→  if (status === 'processed') return '✓ Verified';
   273→  if (status === 'flagged') return '⚠ Flagged';
   274→  if (status === 'pending') return '⏳ Processing';
   275→  return status;
   276→}
