   278→function getDocIcon(type) {
   279→  const icons = {
   280→    resume: '📝',
   281→    education_certificate: '🎓',
   282→    employment_letter: '💼',
   283→    id_document: '🪪',
   284→    certification: '🏆',
   285→    reference_letter: '📨'
   286→  };
   287→  return icons[type] || '📄';
   288→}
   289→
   290→function formatDocType(type) {
   291→  return type.split('_').map(word =>
   292→    word.charAt(0).toUpperCase() + word.slice(1)
   293→  ).join(' ');
   294→}
   295→
   296→function formatDate(dateStr) {
   297→  const date = new Date(dateStr);
   298→  const now = new Date();
   299→  const diffMs = now - date;
   300→  const diffMins = Math.floor(diffMs / 60000);
   301→  const diffHours = Math.floor(diffMs / 3600000);
   302→  const diffDays = Math.floor(diffMs / 86400000);
   303→
   304→  if (diffMins < 60) return `${diffMins}m ago`;
   305→  if (diffHours < 24) return `${diffHours}h ago`;
   306→  if (diffDays < 30) return `${diffDays}d ago`;
   307→
   308→  return date.toLocaleDateString();
   309→}
